// generate-puzzle-data.mjs
// Converts co-the/puzzles.js  →  android/app/src/main/kotlin/.../PuzzleData.kt

import { readFileSync, writeFileSync } from 'fs';
import { PUZZLES } from './co-the/puzzles.js';

const OUT = './android/app/src/main/kotlin/com/xiangqi/cothe/engine/PuzzleData.kt';

const lines = [
  'package com.xiangqi.cothe.engine',
  '',
  '// AUTO-GENERATED by generate-puzzle-data.mjs — do not edit manually',
  '// Source: co-the/puzzles.js',
  `// count: ${PUZZLES.length}`,
  '',
  'data class PuzzleDef(',
  '    val id: Int,',
  '    val title: String,',
  '    val movesToMate: Int,',
  '    val pieces: List<PiecePos>,',
  '    val solution: List<Move>',
  ')',
  '',
  'object PuzzleData {',
  `    val ALL: List<PuzzleDef> = listOf(`,
];

for (const p of PUZZLES) {
  const piecesKt = p.pieces
    .map(pc => `PiecePos("${pc.type}","${pc.color}",${pc.col},${pc.row})`)
    .join(', ');
  const solutionKt = p.solution
    .map(m => `Move(${m.fromCol},${m.fromRow},${m.toCol},${m.toRow})`)
    .join(', ');
  lines.push(`        PuzzleDef(${p.id},"${p.title}",${p.movesToMate},listOf(${piecesKt}),listOf(${solutionKt})),`);
}

lines.push('    )');
lines.push('}');
lines.push('');

writeFileSync(OUT, lines.join('\n'), 'utf8');
console.log(`Generated ${PUZZLES.length} puzzles → ${OUT}`);
